import React, { useState, useEffect } from 'react';
import AOS from 'aos';
import 'aos/dist/aos.css';

// Component Imports
import Hero from './components/sections/Hero';
import FlowerPetals from './components/animations/FlowerPetals';
import Timeline from './components/sections/Timeline';
import Gallery from './components/sections/Gallery';
import RSVPForm from './components/sections/RSVPForm';
import InvitationQR from './components/ui/InvitationQR';
import MusicPlayer from './components/ui/MusicPlayer';
import Navbar from './components/ui/Navbar';
import ThreeRings from './components/animations/ThreeRings';
import Profiles from './components/sections/Profiles';
import VenueMap from './components/ui/VenueMap';
import Events from './components/sections/Events';
import GiftRegistry from './components/sections/GiftRegistry';
import Guestbook from './components/ui/Guestbook';
import ParallaxSection from './components/animations/ParallaxSection';
import GlassCountdown from './components/ui/GlassCountdown';
import FloatingActions from './components/ui/FloatingActions';
import StyleGuide from './components/sections/StyleGuide';
import LiveCounter from './components/ui/LiveCounter';
import SuccessModal from './components/ui/SuccessModal';
import Itinerary from './components/sections/Itinerary';
import Squad from './components/sections/Squad';
import WeatherCard from './components/ui/WeatherCard';

function App() {
  const [submittedData, setSubmittedData] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const handleRSVPSuccess = (data) => {
    setSubmittedData(data);
    setIsModalOpen(true); 
  };

  useEffect(() => {
    try {
      AOS.init({ 
        duration: 1200, 
        once: true,
        offset: 50,
        disable: window.innerWidth < 768 
      });
    } catch (e) {
      console.error("AOS error:", e);
    }
  }, []);

  return (
    <div className="bg-[#FAF9F6] min-h-screen relative selection:bg-[#D4AF37] selection:text-white overflow-x-hidden">
      
      {/* --- Global Layers --- */}
      <Navbar />
      <div className="relative z-[200]">
        <MusicPlayer />
        <FloatingActions />
      </div>
      
      <div className="fixed inset-0 pointer-events-none z-0">
        <FlowerPetals />
      </div>

      <SuccessModal 
        isOpen={isModalOpen} 
        guestName={submittedData?.name} 
        onClose={() => setIsModalOpen(false)} 
      />

      {/* 1. Hero with Weather Integration */}
      <section id="home" className="relative h-screen flex flex-col items-center justify-center">
        <div className="absolute inset-0 z-0"><ThreeRings /></div>
        <div className="text-center z-10 space-y-8 px-4">
          <h1 className="text-6xl md:text-9xl font-serif text-[#D4AF37] italic" data-aos="zoom-in">
            Prabha & Empty
          </h1>
          <div data-aos="fade-up" data-aos-delay="400">
            <GlassCountdown targetDate="2026-12-04" />
          </div>
          <div className="flex flex-col items-center gap-6" data-aos="fade-up" data-aos-delay="600">
            <p className="text-gray-500 tracking-[0.6em] uppercase text-[10px]">The Union of Two Souls</p>
            <WeatherCard />
          </div>
        </div>
      </section>

      {/* 2. Core Information Flow */}
      <Profiles />
      <ParallaxSection />
      <Itinerary />
      
      {/* 3. Story & Squad */}
      <section id="story" className="py-24 max-w-5xl mx-auto px-6 relative z-10">
        <h2 className="text-center font-serif text-5xl italic mb-16" data-aos="fade-up">Our Story</h2>
        <Timeline />
      </section>
      <Squad />

      {/* 4. Visuals & Style */}
      <Events />
      <Gallery />
      <StyleGuide />

      {/* 5. Engagement & Logistics */}
      <LiveCounter />
      <Guestbook />
      <VenueMap />
      <GiftRegistry />

      {/* 6. RSVP Section */}
      <section id="rsvp" className="py-32 bg-[#1A1A1B] text-white relative z-20">
        <div className="max-w-4xl mx-auto px-6 text-center">
          <h2 className="font-serif text-5xl italic text-[#D4AF37] mb-4" data-aos="fade-up">Join Our Joy</h2>
          <p className="text-gray-400 text-[10px] uppercase tracking-widest mb-12">Confirm your presence by Nov 2026</p>
          
          <div className="relative z-30">
            <RSVPForm onSubmissionSuccess={handleRSVPSuccess} />
          </div>

          {submittedData && !isModalOpen && (
            <div className="mt-16 bg-white/5 p-8 rounded-3xl border border-white/10" data-aos="zoom-in">
               <h3 className="font-serif text-2xl mb-6 italic text-[#D4AF37]">See You Soon, {submittedData.name}!</h3>
               <InvitationQR guestName={submittedData.name} />
            </div>
          )}
        </div>
      </section>

      {/* 7. Footer */}
      <footer className="py-20 text-center bg-[#FAF9F6] border-t border-gray-100 relative z-10">
        <div className="font-serif italic text-4xl text-gray-800 mb-6">P & E</div>
        <p className="text-gray-400 uppercase tracking-[0.5em] text-[9px]">
          Prabha & Empty — December 4, 2026
        </p>
      </footer>
    </div>
  );
}

export default App;
